// // This module selects between two inputs based on the select signal S. When S is high (1), the output Y reflects the value of input A; when S is low (0), Y outputs the value of input B.
module top_module(A, B, S, Y);input A, B, S; 
 output reg Y; 
 always @* begin 
  if (S) 
  Y = B; 
  else 
  Y = A; 
 end 
 endmodule
